55	
56	  // --- Alerts tab ---
57	  allAlerts: AlertNotification[] = [];
58	  alertsLoading = true;
59	
60	  // --- Licensing tab ---
61	  allNotifications: LicensingNotification[] = [];
62	  loading = true;
