229	    const s = status.toLowerCase().trim();
230	
231	    const approved = [
232	      'concept approved', 'concept approved with changes',
233	      'packaging concept approved', 'packaging concept approved with changes',
234	      'pre-pro approved', 'pre-pro approved with changes',
235	      'internal concept approval', 'internal pre-pro approval'
236	    ];
237	    if (approved.some(a => s === a)) return '#4caf50';
238	    if (s === 'concept not approved at all') return '#f44336';
239	
240	    const revisions = [
241	      'concept needs revisions', 'concept resubmitted',
242	      'packaging concept needs revisions', 'packaging concept resubmitted',
243	      'pre-pro needs revisions', 'pre-pro resubmitted'
244	    ];
245	    if (revisions.some(r => s === r)) return '#ff9800';
246	
247	    const submitted = [
248	      'concept submitted', 'packaging concept submitted', 'pre-pro submitted',
249	      'ready to submit', 'request pre-pro sample', 'pre-pro photos received'
250	    ];
251	    if (submitted.some(sub => s === sub)) return '#2196f3';
252	
253	    return '#9e9e9e';
254	  }
255	
256	  getAssignorName(notification: LicensingNotification): string {
257	    if (notification.assignor) {
258	      return `${notification.assignor.name || ''} ${notification.assignor.lastname || ''}`.trim();
259	    }
260	    return notification.moduser || 'Unknown';
261	  }
262	
263	  formatDate(dateStr: string): string {
264	    if (!dateStr) return '';
265	    const date = new Date(dateStr);
266	    const now = new Date();
267	    const diffMs = now.getTime() - date.getTime();
268	    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
269	
270	    if (diffDays === 0) return 'Today';
271	    if (diffDays === 1) return 'Yesterday';
272	    if (diffDays < 7) return `${diffDays} days ago`;
273	
274	    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
275	  }
276	
277	  truncate(text: string, maxLen: number = 80): string {
278	    if (!text) return '';
279	    return text.length > maxLen ? text.substring(0, maxLen) + '…' : text;
280	  }
281	}
