21	const TYPE_ICON_MAP: Record<string, { icon: string; colorClass: string }> = {
22	  mention: { icon: 'ic:twotone-alternate-email', colorClass: 'text-primary' },
23	  task_assignment: { icon: 'ic:twotone-assignment-ind', colorClass: 'text-orange' },
24	  approval: { icon: 'ic:twotone-check-circle', colorClass: 'text-green' },
