35	export class ToolbarNotificationsDropdownComponent implements OnInit {
36	  notifications: DropdownNotification[] = [];
37	  loading = true;
38	
39	  icSettings = icSettings;
40	  icChevronRight = icChevronRight;
41	  icClearAll = icClearAll;
42	  icNotificationsOff = icNotificationsOff;
43	  trackById = trackById;
44	
45	  constructor(
46	    private readonly notificationService: NotificationService,
47	    private readonly cd: ChangeDetectorRef,
48	  ) {}
49	
50	  ngOnInit(): void {
51	    this.load();
52	  }
53	
54	  async load(): Promise<void> {
55	    this.loading = true;
56	    this.cd.markForCheck();
57	    try {
58	      const res = await firstValueFrom(this.notificationService.getNotifications());
59	      this.notifications = res.data.map(n => this.toDisplay(n));
60	    } catch {
61	      this.notifications = [];
62	    } finally {
63	      this.loading = false;
64	      this.cd.markForCheck();
65	    }
66	  }
67	
68	  async markRead(notification: DropdownNotification): Promise<void> {
69	    if (notification.read) return;
70	    try {
71	      await firstValueFrom(this.notificationService.markAsRead(notification.id));
72	      notification.read = true;
73	      this.notificationService.refreshCount();
74	      this.cd.markForCheck();
75	    } catch {}
76	  }
77	
78	  async markAllRead(): Promise<void> {
79	    try {
80	      await firstValueFrom(this.notificationService.markAllAsRead());
81	      this.notifications.forEach(n => (n.read = true));
82	      this.notificationService.refreshCount();
83	      this.cd.markForCheck();
84	    } catch {}
85	  }
86	
87	  get unreadCount(): number {
88	    return this.notifications.filter(n => !n.read).length;
89	  }
90	
91	  private toDisplay(item: NotificationItem): DropdownNotification {
92	    const { icon, colorClass } = TYPE_ICON_MAP[item.type] ?? DEFAULT_ICON;
93	    return {
94	      id: item.id,
95	      icon,
96	      colorClass,
97	      label: item.title ?? item.type,
98	      description: item.message ?? '',
99	      datetime: item.created_date ? DateTime.fromISO(item.created_date) : DateTime.local(),
100	      read: !item.unread,
101	    };
102	  }
103	}
