70	  onEditorCreated(editor: any): void {
71	    this.quillEditor = editor;
72	  }
73	
74	  onContentChanged(event: any): void {
75	    const editor = event.editor;
76	    const selection = editor.getSelection();
77	    if (!selection) { this.closeMention(); return; }
78	
79	    const text: string = editor.getText();
80	    const textBefore = text.substring(0, selection.index);
81	    const atIndex = textBefore.lastIndexOf('@');
82	
83	    if (atIndex === -1) { this.closeMention(); return; }
84	
85	    const partial = textBefore.substring(atIndex + 1);
86	    // A space after @ means the mention token is done
87	    if (/[\s\n]/.test(partial)) { this.closeMention(); return; }
88	
89	    this.mentionStart = atIndex;
90	    this.mentionPartial = partial;
91	    this.filteredMentionUsers = this.filterUsers(partial);
92	    this.showMentionPicker = this.filteredMentionUsers.length > 0;
93	  }
94	
95	  onMentionPicked(user: MentionableUser): void {
96	    if (!this.quillEditor) return;
97	    const selection = this.quillEditor.getSelection();
98	    const cursorIndex =
99	      selection?.index ?? this.mentionStart + this.mentionPartial.length + 1;
100	
101	    // Replace from '@' to cursor with the resolved mention handle
102	    this.quillEditor.deleteText(this.mentionStart, cursorIndex - this.mentionStart);
103	    const insertText = `@${user.name} `;
104	    this.quillEditor.insertText(this.mentionStart, insertText, 'user');
105	    this.quillEditor.setSelection(this.mentionStart + insertText.length);
106	    this.closeMention();
107	  }
