114	  private filterUsers(partial: string): MentionableUser[] {
115	    if (!partial) return this.mentionUsers.slice(0, 8);
116	    const q = partial.toLowerCase();
117	    return this.mentionUsers
118	      .filter(
119	        (u) =>
120	          (u.name ?? '').toLowerCase().startsWith(q) ||
121	          (u.lastname ?? '').toLowerCase().startsWith(q) ||
122	          `${u.name ?? ''} ${u.lastname ?? ''}`.toLowerCase().includes(q)
123	      )
124	      .slice(0, 8);
125	  }
